using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPageIndexAndTotalPages()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var result = new PaginatedList<string>(items, 10, 2, 3);

        // Assert
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(4, result.TotalPages); // ceil(10/3) = 4
    }

    [Fact]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<int> { 1, 2, 3 };

        // Act
        var result = new PaginatedList<int>(items, 10, 1, 5);

        // Assert
        Assert.Equal(3, result.Count);
        Assert.Contains(1, result);
        Assert.Contains(2, result);
        Assert.Contains(3, result);
    }

    [Theory]
    [InlineData(10, 5, 2)]  // ceil(10/5) = 2
    [InlineData(11, 5, 3)]  // ceil(11/5) = 3
    [InlineData(1, 10, 1)]  // ceil(1/10) = 1
    [InlineData(0, 10, 0)]  // ceil(0/10) = 0
    [InlineData(100, 10, 10)] // ceil(100/10) = 10
    public void TotalPages_CalculatedCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        // Arrange & Act
        var result = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        // Assert
        Assert.Equal(expectedTotalPages, result.TotalPages);
    }

    [Theory]
    [InlineData(1, false)]   // page 1 has no previous page
    [InlineData(2, true)]    // page 2 has previous page
    [InlineData(5, true)]    // page 5 has previous page
    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
    {
        // Arrange & Act
        var result = new PaginatedList<int>(new List<int>(), 100, pageIndex, 10);

        // Assert
        Assert.Equal(expected, result.HasPreviousPage);
    }

    [Theory]
    [InlineData(1, 10, 10, false)]  // page 1 of 1 (10 items, 10 per page)
    [InlineData(1, 10, 5, true)]    // page 1 of 2 (10 items, 5 per page)
    [InlineData(2, 10, 5, false)]   // page 2 of 2 (10 items, 5 per page)
    [InlineData(1, 100, 10, true)]  // page 1 of 10
    [InlineData(10, 100, 10, false)] // page 10 of 10
    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int count, int pageSize, bool expected)
    {
        // Arrange & Act
        var result = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

        // Assert
        Assert.Equal(expected, result.HasNextPage);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(5, result.TotalPages); // ceil(50/10) = 5
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]); // Second page starts at item 11
        Assert.Equal(20, result[9]); // Second page ends at item 20
    }

    [Fact]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(1, result[0]);
        Assert.Equal(10, result[9]);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.Equal(3, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(5, result.Count); // Only 5 items on the last page
        Assert.Equal(21, result[0]);
        Assert.Equal(25, result[4]);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(0, result.TotalPages);
        Assert.Empty(result);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void Create_SingleItem_ReturnsOnePageWithOneItem()
    {
        // Arrange
        var source = new[] { 42 }.AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(1, result.TotalPages);
        Assert.Single(result);
        Assert.Equal(42, result[0]);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }
}

