+using System;
+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+using Xunit;
+
+namespace ContosoUniversity.Tests.Services;
+
+public class NotificationServiceTests : IDisposable
+{
+    private readonly NotificationService _service;
+
+    public NotificationServiceTests()
+    {
+        _service = new NotificationService();
+        // Drain the static queue before each test to avoid interference
+        while (_service.ReceiveNotification() != null) { }
+    }
+
+    public void Dispose()
+    {
+        _service.Dispose();
+    }
+
+    [Fact]
+    public void SendNotification_WithDisplayName_EnqueuesNotification()
+    {
+        // Act
+        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("Student", notification.EntityType);
+        Assert.Equal("1", notification.EntityId);
+        Assert.Equal("CREATE", notification.Operation);
+        Assert.Equal("admin", notification.CreatedBy);
+        Assert.False(notification.IsRead);
+        Assert.Contains("John Doe", notification.Message);
+        Assert.Contains("created", notification.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
+    {
+        // Act
+        _service.SendNotification("Course", "42", EntityOperation.UPDATE);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("Course", notification.EntityType);
+        Assert.Equal("42", notification.EntityId);
+        Assert.Equal("UPDATE", notification.Operation);
+        Assert.Contains("ID: 42", notification.Message);
+        Assert.Contains("updated", notification.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithoutUserName_DefaultsToSystem()
+    {
+        // Act
+        _service.SendNotification("Department", "5", "Science", EntityOperation.DELETE);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("System", notification.CreatedBy);
+    }
+
+    [Fact]
+    public void SendNotification_WithUserName_SetsCreatedBy()
+    {
+        // Act
+        _service.SendNotification("Student", "3", "Jane Smith", EntityOperation.CREATE, "teacher1");
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("teacher1", notification.CreatedBy);
+    }
+
+    [Theory]
+    [InlineData(EntityOperation.CREATE, "created")]
+    [InlineData(EntityOperation.UPDATE, "updated")]
+    [InlineData(EntityOperation.DELETE, "deleted")]
+    public void SendNotification_GeneratesCorrectMessageForOperation(EntityOperation operation, string expectedVerb)
+    {
+        // Act
+        _service.SendNotification("Instructor", "7", "Dr. Smith", operation);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Contains(expectedVerb, notification.Message);
+        Assert.Contains("Dr. Smith", notification.Message);
+    }
+
+    [Fact]
+    public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
+    {
+        // Act
+        var result = _service.ReceiveNotification();
+
+        // Assert
+        Assert.Null(result);
+    }
+
+    [Fact]
+    public void ReceiveNotification_ReturnsNotificationsInFIFOOrder()
+    {
+        // Arrange
+        _service.SendNotification("Student", "1", "First", EntityOperation.CREATE);
+        _service.SendNotification("Student", "2", "Second", EntityOperation.UPDATE);
+        _service.SendNotification("Student", "3", "Third", EntityOperation.DELETE);
+
+        // Act & Assert
+        var first = _service.ReceiveNotification();
+        Assert.Equal("1", first.EntityId);
+
+        var second = _service.ReceiveNotification();
+        Assert.Equal("2", second.EntityId);
+
+        var third = _service.ReceiveNotification();
+        Assert.Equal("3", third.EntityId);
+
+        var empty = _service.ReceiveNotification();
+        Assert.Null(empty);
+    }
+
+    [Fact]
+    public void SendNotification_SetsCreatedAtToApproximatelyNow()
+    {
+        // Arrange
+        var before = DateTime.Now;
+
+        // Act
+        _service.SendNotification("Course", "1", "Math", EntityOperation.CREATE);
+
+        // Assert
+        var after = DateTime.Now;
+        var notification = _service.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.InRange(notification.CreatedAt, before, after);
+    }
+
+    [Fact]
+    public void SendNotification_SetsIsReadToFalse()
+    {
+        // Act
+        _service.SendNotification("Department", "1", "English", EntityOperation.CREATE);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.False(notification.IsRead);
+    }
+
+    [Fact]
+    public void MarkAsRead_DoesNotThrow()
+    {
+        // Act & Assert (MarkAsRead is a no-op but should not throw)
+        var exception = Record.Exception(() => _service.MarkAsRead(1));
+        Assert.Null(exception);
+    }
+
+    [Fact]
+    public void Dispose_DoesNotThrow()
+    {
+        // Act & Assert
+        var service = new NotificationService();
+        var exception = Record.Exception(() => service.Dispose());
+        Assert.Null(exception);
+    }
+
+    [Fact]
+    public void SendNotification_CreateOperation_MessageFormat_WithDisplayName()
+    {
+        // Act
+        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.Equal("New Student 'John Doe' has been created", notification.Message);
+    }
+
+    [Fact]
+    public void SendNotification_UpdateOperation_MessageFormat_WithDisplayName()
+    {
+        // Act
+        _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
+    }
+
+    [Fact]
+    public void SendNotification_DeleteOperation_MessageFormat_WithDisplayName()
+    {
+        // Act
+        _service.SendNotification("Department", "5", "Science", EntityOperation.DELETE);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.Equal("Department 'Science' has been deleted", notification.Message);
+    }
+
+    [Fact]
+    public void SendNotification_CreateOperation_MessageFormat_WithoutDisplayName()
+    {
+        // Act
+        _service.SendNotification("Student", "42", EntityOperation.CREATE);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.Equal("New Student (ID: 42) has been created", notification.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithNullDisplayName_UsesIdInMessage()
+    {
+        // Act
+        _service.SendNotification("Course", "99", null, EntityOperation.UPDATE);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.Equal("Course (ID: 99) has been updated", notification.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
+    {
+        // Act
+        _service.SendNotification("Course", "99", "", EntityOperation.DELETE);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.Equal("Course (ID: 99) has been deleted", notification.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
+    {
+        // Act
+        _service.SendNotification("Course", "99", "   ", EntityOperation.CREATE);
+
+        // Assert
+        var notification = _service.ReceiveNotification();
+        Assert.Equal("New Course (ID: 99) has been created", notification.Message);
+    }
+}
+

