using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        SeedStudents();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2010, 9, 1) },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2013, 9, 1) },
            new Student { ID = 4, FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { ID = 5, FirstMidName = "Yan", LastName = "Li", EnrollmentDate = new DateTime(2012, 9, 1) }
        );
        _context.SaveChanges();
    }

    [Fact]
    public void Index_ReturnsViewResult_WithPaginatedList()
    {
        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(5, model.Count);
    }

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Alexander", model[0].LastName);
        Assert.Equal("Alonso", model[1].LastName);
        Assert.Equal("Anand", model[2].LastName);
    }

    [Fact]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Act
        var result = _controller.Index("name_desc", null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Li", model[0].LastName);
        Assert.Equal("Barzdukas", model[1].LastName);
    }

    [Fact]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Act
        var result = _controller.Index("Date", null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Alexander", model[0].LastName); // 2010
    }

    [Fact]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        // Act
        var result = _controller.Index("date_desc", null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Anand", model[0].LastName); // 2013
    }

    [Fact]
    public void Index_SearchString_FiltersStudents()
    {
        // Act
        var result = _controller.Index(null, null, "Al", null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(2, model.Count); // Alexander and Alonso
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersStudents()
    {
        // Act
        var result = _controller.Index(null, null, "Carson", null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchString_ResetsPage()
    {
        // Act - when searchString is provided, page should reset to 1
        var result = _controller.Index(null, null, "Al", 3);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_CurrentFilter_MaintainsSearch()
    {
        // Act - when no new search, currentFilter is used
        var result = _controller.Index(null, "An", null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(2, model.Count); // Anand and Alonso (contains "An")
    }

    [Fact]
    public void Details_WithValidId_ReturnsViewResult()
    {
        // Arrange - add enrollment for Include to work
        _context.Courses.Add(new Course { CourseID = 100, Title = "Test", Credits = 3, DepartmentID = 0 });
        _context.Enrollments.Add(new Enrollment { StudentID = 1, CourseID = 100, Grade = Grade.A });
        _context.SaveChanges();

        // Act
        var result = _controller.Details(1);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
        Assert.Equal("Carson", model.FirstMidName);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Create();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_Post_ValidStudent_SavesStudentToDb()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };

        // Act
        _controller.Create(student);

        // Assert
        var savedStudent = _context.Students.FirstOrDefault(s => s.LastName == "Student");
        Assert.NotNull(savedStudent);
        Assert.Equal("New", savedStudent.FirstMidName);
        Assert.Equal(new DateTime(2024, 1, 15), savedStudent.EnrollmentDate);
    }

    [Fact]
    public void Create_Post_DefaultEnrollmentDate_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Create_Post_DateBeforeSqlMin_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(1700, 1, 1)
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Edit_Get_WithValidId_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Edit(1);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(999);

        // Assert
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            ID = 1,
            FirstMidName = "Updated",
            LastName = "Alexander",
            EnrollmentDate = new DateTime(2010, 9, 1)
        };
        // Detach existing tracked entity
        var existing = _context.Students.Find(1);
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        // Act
        var result = _controller.Edit(student);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_Post_DefaultDate_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            ID = 1,
