using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;

    public CoursesControllerTests()
    {
        _context = TestDbContextFactory.Create();
        SeedData();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns("/tmp/webroot");
        _envMock.Setup(e => e.ContentRootPath).Returns("/tmp/content");
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedData()
    {
        _context.Departments.Add(new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1)
        });
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 1 }
        );
        _context.SaveChanges();
    }

    [Fact]
    public void Index_ReturnsViewResult_WithCourseList()
    {
        // Act
        var result = _controller.Index();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(viewResult.Model);
        Assert.Equal(3, model.Count);
    }

    [Fact]
    public void Details_WithValidId_ReturnsViewWithCourse()
    {
        // Act
        var result = _controller.Details(1050);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
        Assert.Equal(3, model.Credits);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsView()
    {
        // Act
        var result = _controller.Create();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.IsType<Course>(viewResult.Model);
    }

    [Fact]
    public void Create_Post_ValidCourse_RedirectsToIndex()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        // Act
        var result = _controller.Create(course, null);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_Post_ValidCourse_SavesToDB()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 8888,
            Title = "Physics",
            Credits = 4,
            DepartmentID = 1
        };

        // Act
        _controller.Create(course, null);

        // Assert
        var saved = _context.Courses.Find(8888);
        Assert.NotNull(saved);
        Assert.Equal("Physics", saved.Title);
        Assert.Equal(4, saved.Credits);
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        var course = new Course { CourseID = 7777, Title = "Bad", Credits = 3, DepartmentID = 1 };
        _controller.ModelState.AddModelError("Title", "Title error");

        // Act
        var result = _controller.Create(course, null);

        // Assert
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Edit_Get_WithValidId_ReturnsViewWithCourse()
    {
        // Act
        var result = _controller.Edit(1050);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
    }

    [Fact]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(9999);

        // Assert
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Post_ValidCourse_RedirectsToIndex()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 1050,
            Title = "Updated Chemistry",
            Credits = 4,
            DepartmentID = 1
        };
        // Detach existing tracked entity
        var existing = _context.Courses.Find(1050);
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        // Act
        var result = _controller.Edit(course, null);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
        _controller.ModelState.AddModelError("Title", "Error");

        // Act
        var result = _controller.Edit(course, null);

        // Assert
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Delete_Get_WithValidId_ReturnsViewWithCourse()
    {
        // Act
        var result = _controller.Delete(1050);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
    }

    [Fact]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        // Act
        var result = _controller.DeleteConfirmed(1050);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Null(_context.Courses.Find(1050));
    }

    [Fact]
    public void DeleteConfirmed_DecreasesCount()
    {
        // Arrange
        var initialCount = _context.Courses.Count();

        // Act
        _controller.DeleteConfirmed(4022);

        // Assert
        Assert.Equal(initialCount - 1, _context.Courses.Count());
    }

    [Fact]
    public void Index_IncludesDepartmentData()
    {
        // Act
        var result = _controller.Index();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(viewResult.Model);
        Assert.All(model, course => Assert.NotNull(course.Department));
    }
}

