using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        SeedData();
        _controller = new InstructorsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedData()
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var courses = new[]
        {
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 }
        };
        _context.Courses.AddRange(courses);
        _context.SaveChanges();

        var instructors = new[]
        {
            new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = new DateTime(1995, 3, 11) },
            new Instructor { ID = 2, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = new DateTime(2002, 7, 6) },
            new Instructor { ID = 3, FirstMidName = "Roger", LastName = "Harui", HireDate = new DateTime(1998, 7, 1) }
        };
        _context.Instructors.AddRange(instructors);
        _context.SaveChanges();

        _context.Set<OfficeAssignment>().Add(new OfficeAssignment { InstructorID = 2, Location = "Smith 17" });
        _context.SaveChanges();

        _context.Set<CourseAssignment>().AddRange(
            new CourseAssignment { InstructorID = 1, CourseID = 1050 },
            new CourseAssignment { InstructorID = 2, CourseID = 4022 }
        );
        _context.SaveChanges();
    }

    [Fact]
    public void Index_NoSelection_ReturnsViewWithAllInstructors()
    {
        // Act
        var result = _controller.Index(null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.Equal(3, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_ReturnsCoursesForInstructor()
    {
        // Act
        var result = _controller.Index(1, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses); // Instructor 1 has course 1050
        Assert.Equal("Chemistry", model.Courses.First().Title);
    }

    [Fact]
    public void Index_InstructorsOrderedByLastName()
    {
        // Act
        var result = _controller.Index(null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        var instructorNames = model.Instructors.Select(i => i.LastName).ToList();
        Assert.Equal("Abercrombie", instructorNames[0]);
        Assert.Equal("Fakhouri", instructorNames[1]);
        Assert.Equal("Harui", instructorNames[2]);
    }

    [Fact]
    public void Details_WithValidId_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Details(1);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", model.LastName);
        Assert.Equal("Kim", model.FirstMidName);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(999);

        // Assert
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Create();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.NotNull(model.CourseAssignments);
        Assert.Empty(model.CourseAssignments);
    }

    [Fact]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2020, 1, 1)
        };

        // Act
        var result = _controller.Create(instructor, null);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
